1029	/// Atomically reads data from `src`.
1030	///
1031	/// This operation uses the `Acquire` ordering. If possible, an atomic instructions is used, and a
1032	/// global lock otherwise.
1033	unsafe fn atomic_load<T>(src: *mut T) -> T
1034	where
1035	    T: Copy,
1036	{
1037	    atomic! {
1038	        T, a,
1039	        {
1040	            a = unsafe { &*(src as *const _ as *const _) };
1041	            unsafe { mem::transmute_copy(&a.load(Ordering::Acquire)) }
1042	        },
1043	        {
1044	            let lock = lock(src as usize);
1045	
1046	            // Try doing an optimistic read first.
1047	            if let Some(stamp) = lock.optimistic_read() {
1048	                // We need a volatile read here because other threads might concurrently modify the
1049	                // value. In theory, data races are *always* UB, even if we use volatile reads and
1050	                // discard the data when a data race is detected. The proper solution would be to
1051	                // do atomic reads and atomic writes, but we can't atomically read and write all
1052	                // kinds of data since `AtomicU8` is not available on stable Rust yet.
1053	                // Load as `MaybeUninit` because we may load a value that is not valid as `T`.
1054	                let val = unsafe { ptr::read_volatile(src.cast::<MaybeUninit<T>>()) };
1055	
1056	                if lock.validate_read(stamp) {
1057	                    return unsafe { val.assume_init() };
1058	                }
1059	            }
1060	
1061	            // Grab a regular write lock so that writers don't starve this load.
1062	            let guard = lock.write();
1063	            let val = unsafe { ptr::read(src) };
1064	            // The value hasn't been changed. Drop the guard without incrementing the stamp.
1065	            guard.abort();
1066	            val
1067	        }
1068	    }
1069	}
